{'path': '/bin/sql', 'stdin': 'WITH archived AS (
  SELECT * FROM payments WHERE basket_archived = 1
), cust_stats AS (
  SELECT customer_id, COUNT(*) AS total_payments FROM archived GROUP BY customer_id
), method_counts AS (
  SELECT customer_id, payment_method_fingerprint, COUNT(*) AS method_n FROM archived GROUP BY customer_id, payment_method_fingerprint
), device_counts AS (
  SELECT customer_id, device_fingerprint, COUNT(*) AS device_n FROM archived GROUP BY customer_id, device_fingerprint
), enriched AS (
  SELECT a.id, a.path, a.customer_id, a.store_id, a.created_at, a.payment_method_fingerprint, a.device_fingerprint,
         cs.total_payments, mc.method_n, dc.device_n
  FROM archived a
  JOIN cust_stats cs ON cs.customer_id = a.customer_id
  JOIN method_counts mc ON mc.customer_id = a.customer_id AND mc.payment_method_fingerprint = a.payment_method_fingerprint
  JOIN device_counts dc ON dc.customer_id = a.customer_id AND dc.device_fingerprint = a.device_fingerprint
)
SELECT * FROM enriched
WHERE total_payments >= 5 AND method_n = 1 AND device_n = 1
ORDER BY total_payments DESC, customer_id, created_at
LIMIT 100;'}
